import React, { useMemo, useState } from 'react';
import MangaCard from './MangaCard';
import './CatalogGrid.css';

const PAGE_SIZE = 6;

const baseData = [
  {
    id: 1,
    title: 'Berserk',
    type: 'Manga',
    author: 'Kentaro Miura',
    cover: 'https://placehold.co/400x600/ff6b6b/white?text=Berserk',
    rating: 4.9,
    chapters: 363,
    views: 1250000,
    status: 'Completed',
    genres: ['Drama', 'Dark Fantasy', 'Action']
  },
  {
    id: 2,
    title: 'Solo Leveling',
    type: 'Manhwa',
    author: 'Chugong',
    cover: 'https://placehold.co/400x600/4ecdc4/white?text=Solo+Leveling',
    rating: 4.8,
    chapters: 179,
    views: 980000,
    status: 'Completed',
    genres: ['Action', 'Fantasy']
  },
  {
    id: 3,
    title: 'Tower of God',
    type: 'Manhwa',
    author: 'SIU',
    cover: 'https://placehold.co/400x600/45b7d1/white?text=Tower+of+God',
    rating: 4.7,
    chapters: 560,
    views: 850000,
    status: 'Ongoing',
    genres: ['Fantasy', 'Adventure']
  },
  {
    id: 4,
    title: 'One Piece',
    type: 'Manga',
    author: 'Eiichiro Oda',
    cover: 'https://placehold.co/400x600/96ceb4/white?text=One+Piece',
    rating: 4.9,
    chapters: 1085,
    views: 1500000,
    status: 'Ongoing',
    genres: ['Action', 'Adventure', 'Comedy']
  },
  {
    id: 5,
    title: 'Attack on Titan',
    type: 'Manga',
    author: 'Hajime Isayama',
    cover: 'https://placehold.co/400x600/ffa726/white?text=Attack+on+Titan',
    rating: 4.8,
    chapters: 139,
    views: 1200000,
    status: 'Completed',
    genres: ['Action', 'Drama', 'Fantasy']
  },
  {
    id: 6,
    title: 'Naruto',
    type: 'Manga',
    author: 'Masashi Kishimoto',
    cover: 'https://placehold.co/400x600/a55eea/white?text=Naruto',
    rating: 4.7,
    chapters: 700,
    views: 1100000,
    status: 'Completed',
    genres: ['Action', 'Adventure']
  },
  {
    id: 7,
    title: 'Jujutsu Kaisen',
    type: 'Manga',
    author: 'Gege Akutami',
    cover: 'https://placehold.co/400x600/ff9ff3/white?text=Jujutsu+Kaisen',
    rating: 4.6,
    chapters: 230,
    views: 800000,
    status: 'Ongoing',
    genres: ['Action', 'Horror']
  },
  {
    id: 8,
    title: 'Demon Slayer',
    type: 'Manga',
    author: 'Koyoharu Gotouge',
    cover: 'https://placehold.co/400x600/1dd1a1/white?text=Demon+Slayer',
    rating: 4.5,
    chapters: 205,
    views: 950000,
    status: 'Completed',
    genres: ['Action', 'Fantasy']
  }
];

const getDataByMode = (mode) => {
  switch (mode) {
    case 'reading-now':
      return [...baseData].sort((a, b) => b.views - a.views).slice(0, 6);
    case 'collections':
      return baseData.map((item) => ({
        ...item,
        id: item.id + 1000,
        type: 'Collection',
        title: `${item.title} Essentials`
      }));
    case 'reviews':
      return baseData.map((item) => ({
        ...item,
        id: item.id + 2000,
        type: 'Reviewed',
        title: `${item.title} Review`
      }));
    case 'titles':
    case 'all':
    default:
      return baseData;
  }
};

const normalizeType = (value) => value.toLowerCase().replace(/\s+/g, '-');

const sortItems = (items, sortBy) => {
  const sorted = [...items];
  switch (sortBy) {
    case 'newest':
      return sorted.sort((a, b) => b.id - a.id);
    case 'rating':
      return sorted.sort((a, b) => b.rating - a.rating);
    case 'views':
      return sorted.sort((a, b) => b.views - a.views);
    case 'chapters':
      return sorted.sort((a, b) => b.chapters - a.chapters);
    case 'popular':
    default:
      return sorted.sort((a, b) => b.views - a.views);
  }
};

const CatalogGrid = ({ filters, mode = 'all', heading = 'Catalog', onResetFilters }) => {
  const [viewMode, setViewMode] = useState('grid');
  const [currentPage, setCurrentPage] = useState(1);

  const filteredData = useMemo(() => {
    const modeData = getDataByMode(mode);
    const filtered = modeData.filter((item) => {
      if (filters.type !== 'all' && normalizeType(item.type) !== normalizeType(filters.type)) {
        return false;
      }
      if (filters.genres.length > 0 && !filters.genres.some((genre) => item.genres.includes(genre))) {
        return false;
      }
      return true;
    });
    return sortItems(filtered, filters.sortBy);
  }, [filters, mode]);

  const totalPages = Math.max(1, Math.ceil(filteredData.length / PAGE_SIZE));
  const safeCurrentPage = Math.min(currentPage, totalPages);
  const paginatedData = filteredData.slice((safeCurrentPage - 1) * PAGE_SIZE, safeCurrentPage * PAGE_SIZE);

  const goToPage = (page) => setCurrentPage(Math.min(Math.max(page, 1), totalPages));

  return (
    <div className="catalog-grid">
      <div className="grid-header">
        <div className="results-info">
          <h3><i className="fas fa-book"></i> {heading}: <span className="count">{filteredData.length}</span></h3>
          <p className="filter-info">
            {filters.type !== 'all' && `Type: ${filters.type}`}
            {filters.genres.length > 0 && ` • Genres: ${filters.genres.join(', ')}`}
          </p>
        </div>

        <div className="grid-controls">
          <div className="view-controls">
            <span className="view-label">View:</span>
            <button
              className={`view-btn ${viewMode === 'grid' ? 'active' : ''}`}
              onClick={() => setViewMode('grid')}
            >
              <i className="fas fa-th-large"></i>
            </button>
            <button
              className={`view-btn ${viewMode === 'list' ? 'active' : ''}`}
              onClick={() => setViewMode('list')}
            >
              <i className="fas fa-list"></i>
            </button>
          </div>
        </div>
      </div>

      {filteredData.length > 0 ? (
        <div className={`grid-content ${viewMode}-view`}>
          {paginatedData.map((item) => (
            <MangaCard key={item.id} manga={item} viewMode={viewMode} />
          ))}
        </div>
      ) : (
        <div className="no-results">
          <div className="no-results-content">
            <i className="fas fa-search"></i>
            <h3>No results found</h3>
            <p>Try changing filters or search criteria.</p>
            <button className="reset-btn" onClick={onResetFilters}>
              <i className="fas fa-redo"></i>
              Reset filters
            </button>
          </div>
        </div>
      )}

      {filteredData.length > 0 && (
        <div className="pagination">
          <button className="page-btn" onClick={() => goToPage(safeCurrentPage - 1)} disabled={safeCurrentPage === 1}>
            <i className="fas fa-chevron-left"></i>
          </button>
          {Array.from({ length: totalPages }, (_, i) => i + 1).map((page) => (
            <button
              key={page}
              className={`page-btn ${safeCurrentPage === page ? 'active' : ''}`}
              onClick={() => goToPage(page)}
            >
              {page}
            </button>
          ))}
          <button className="page-btn" onClick={() => goToPage(safeCurrentPage + 1)} disabled={safeCurrentPage === totalPages}>
            <i className="fas fa-chevron-right"></i>
          </button>
        </div>
      )}
    </div>
  );
};

export default CatalogGrid;
